                    background: rgba(255, 255, 255, 0.05);
                    border: 1px solid rgba(255, 255, 255, 0.1);
                    color: white;
                    padding: 12px 16px;
                    border-radius: 12px;
                    transition: all 0.3s ease;
                }
                .form-control:focus {
                    background: rgba(255, 255, 255, 0.1);
                    border-color: #3b82f6;
                    box-shadow: 0 0 0 4px rgba(59, 130, 246, 0.1);
                    color: white;
                }
                .btn-primary {
                    background: #3b82f6;
                    border: none;
                    padding: 14px;
                    border-radius: 12px;
                    font-weight: 600;
                    transition: all 0.3s ease;
                }
