                    align-items: center;
                    text-align: center;
                    margin: 24px 0;
                    color: #94a3b8; /* Increased contrast from #475569 */
                }
                .divider::before, .divider::after {
                    content: '';
                    flex: 1;
                    border-bottom: 1px solid #334155;
                }
