                </div>

                <button onClick={handleGoogleLogin} className="btn btn-google w-100">
                    <i className="bi bi-google"></i>
                    Continue with Google
                </button>

                <div className="divider">
                    <span>OR CONTINUE WITH EMAIL</span>
                </div>

