                    <p className="mb-0 text-white opacity-75">
                        New to the hub? {' '}
                        <Link to="/register" className="text-white text-decoration-none fw-bold hover-underline">Create Account</Link>
                    </p>
                </div>
            </div>
        </div>
    );
};

